import React, { useEffect, useState } from "react";
import axios from "axios";
import { useNavigate } from "react-router-dom";
import { motion } from "framer-motion";

const DashboardCards = () => {

  const navigate = useNavigate();
  const userId = "user123";

  const [total, setTotal] = useState(0);
  const [completed, setCompleted] = useState(0);
  const [time, setTime] = useState(new Date());

  const percent =
    total === 0 ? 0 : Math.round((completed / total) * 100);

  // FETCH TODOS
  useEffect(() => {
    const fetchTodos = async () => {
      try {
        const res = await axios.get(
          `http://localhost:5001/api/todos?userId=${userId}`
        );

        const todos = res.data;

        setTotal(todos.length);

        const completedCount = todos.filter(
          (todo) => todo.completed
        ).length;

        setCompleted(completedCount);

      } catch (err) {
        console.error("DASHBOARD ERROR 👉", err);
      }
    };

    fetchTodos();
  }, []);

  // LIVE TIME
  useEffect(() => {
    const interval = setInterval(() => {
      setTime(new Date());
    }, 1000);

    return () => clearInterval(interval);
  }, []);

  const handleAddTask = () => {
    navigate("/addTask");
  };

  return (
    <div className="bg-gradient-to-br from-[#0f172a] via-[#020617] to-[#020617] p-6">

      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        className="grid sm:grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6"
      >

        {/* 🔥 NEW MODERN CARD (REPLACED 1 + 2) */}
        <motion.div
          initial={{ y: 50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.03 }}
          className="col-span-1 md:col-span-2 lg:col-span-2 relative bg-white/10 backdrop-blur-xl border border-white/20 p-6 rounded-3xl text-white shadow-2xl overflow-hidden"
        >

          {/* Glow */}
          <div className="absolute inset-0 bg-gradient-to-br from-indigo-500/10 via-purple-500/10 to-cyan-500/10 blur-2xl" />

          <div className="relative z-10 space-y-6">

            {/* HEADER */}
            <div>
              <h2 className="text-xl font-semibold">
                👋 Good Evening, Priyanshu
              </h2>
              <p className="text-sm opacity-70">
                Here's what's happening today
              </p>
            </div>

            {/* TIME */}
            <div className="flex items-center justify-between">

              <div>
                <h1 className="text-5xl font-bold tracking-wide">
                  {time.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </h1>
                <p className="text-sm opacity-70 mt-1">
                  {time.toDateString()}
                </p>
              </div>

              {/* MINI CLOCK UI */}
              <div className="w-20 h-20 rounded-full bg-gradient-to-br from-purple-500 to-indigo-500 flex items-center justify-center shadow-lg">
                <div className="w-3 h-3 bg-white rounded-full" />
              </div>

            </div>

            {/* INFO ROW */}
            <div className="grid grid-cols-3 gap-4 text-center text-sm">

              <div className="bg-white/5 rounded-xl p-3">
                <p className="opacity-70">Day</p>
                <p className="font-semibold">{time.toLocaleDateString('en-US', { weekday: 'long' })}</p>
              </div>

              <div className="bg-white/5 rounded-xl p-3">
                <p className="opacity-70">Tasks</p>
                <p className="font-semibold">{total}</p>
              </div>

              <div className="bg-white/5 rounded-xl p-3">
                <p className="opacity-70">Progress</p>
                <p className="font-semibold">{percent}%</p>
              </div>

            </div>

            {/* STATS */}
            <div className="grid grid-cols-4 gap-4 text-center">

              <div className="bg-white/5 rounded-xl p-4">
                <p className="text-xl font-bold">{total}</p>
                <p className="text-xs opacity-70">Total</p>
              </div>

              <div className="bg-white/5 rounded-xl p-4">
                <p className="text-xl font-bold text-green-400">{completed}</p>
                <p className="text-xs opacity-70">Done</p>
              </div>

              <div className="bg-white/5 rounded-xl p-4">
                <p className="text-xl font-bold text-yellow-300">{total - completed}</p>
                <p className="text-xs opacity-70">Left</p>
              </div>

              <div className="bg-white/5 rounded-xl p-4">
                <p className="text-xl font-bold text-blue-400">{percent}%</p>
                <p className="text-xs opacity-70">Progress</p>
              </div>

            </div>

            {/* PROGRESS BAR */}
            <div>
              <div className="w-full h-2 bg-white/20 rounded-full overflow-hidden">
                <motion.div
                  initial={{ width: 0 }}
                  animate={{ width: `${percent}%` }}
                  transition={{ duration: 1 }}
                  className="h-full bg-gradient-to-r from-purple-500 to-indigo-500"
                />
              </div>
            </div>

            {/* MOTIVATION */}
            <div className="bg-gradient-to-r from-purple-500/20 to-pink-500/20 p-4 rounded-xl text-center text-sm">
              {percent === 100
                ? "🔥 All tasks completed!"
                : "🚀 Small progress is still progress"}
            </div>

            <button
              onClick={handleAddTask}
              className="w-full py-2 bg-white text-black rounded-xl font-semibold hover:scale-105 transition"
            >
              + Add Task
            </button>

          </div>

        </motion.div>

        {/* 3. CALENDAR */}
        <motion.div
          initial={{ y: 50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.05 }}
          className="bg-white/10 backdrop-blur-xl border border-white/20 p-6 rounded-3xl text-white shadow-2xl"
        >
          <h3 className="text-lg font-semibold mb-4">📅 Calendar</h3>

          <div className="grid grid-cols-7 gap-2 text-center text-sm">
            {["Sun","Mon","Tue","Wed","Thu","Fri","Sat"].map((d,i) => (
              <div key={i} className="opacity-70">{d}</div>
            ))}

            {[...Array(30)].map((_, i) => (
              <motion.div
                whileHover={{ scale: 1.2 }}
                key={i}
                className={`p-2 rounded-lg cursor-pointer ${
                  i === new Date().getDate() - 1
                    ? "bg-white text-black font-bold"
                    : "bg-white/10"
                }`}
              >
                {i + 1}
              </motion.div>
            ))}
          </div>
        </motion.div>

        {/* 4. PROFILE */}
        <motion.div
          initial={{ y: 50, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          whileHover={{ scale: 1.05 }}
          className="bg-white/10 backdrop-blur-xl border border-white/20 p-6 rounded-3xl text-white shadow-2xl text-center"
        >

          <motion.img
            whileHover={{ scale: 1.1 }}
            src="https://i.pravatar.cc/100"
            className="w-24 h-24 rounded-full mx-auto border-4 border-white shadow-lg"
            alt=""
          />

          <h3 className="mt-4 text-lg font-semibold">Priyanshu</h3>

          <button className="mt-4 px-5 py-2 bg-white text-black rounded-xl hover:scale-105 transition">
            Edit Profile
          </button>

        </motion.div>

      </motion.div>

    </div>
  );
};

export default DashboardCards;
